{
    public static ColorValueObject Red => new ColorValueObject(Color.Red);
    public static ColorValueObject Green => new ColorValueObject(Color.Green);
    public static ColorValueObject Blue => new ColorValueObject(Color.Blue);

    private readonly Color _color;

    public ColorValueObject(Color color)
    {
        _color = color;
    }

    public Color Color => _color;

    public override string ToString() => _color.ToString();
}

public class Product
