```typescript
import { createContext, useContext, useState } from 'react';
import { notify } from './notification.helpers';

interface NotificationContextInterface {
  notify: (props: Parameters<typeof notify>[1]) => void;
}

const NotificationContext = createContext<NotificationContextInterface | null>(null);

const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);

  const notify = async (props: Parameters<typeof notify>[1]) => {
    if (!notificationElem) return;

    try {
      await notificationElem.open({
        heading: props.heading,
        subheading: props.subheading,
        type: props.type,
      });
      setIsNotificationOpen(true);
    } catch (error) {
      console.error(error);
    }
  };

  return { notify, isNotificationOpen };
};

export { NotificationContext, useNotification };
